addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

const MAX_TTL = 86400; // 24 hours maximum
const MIN_TTL = 60; // 1 minute minimum
const DEFAULT_TTL = 3600; // 1 hour default
const MAX_CACHE_KEY_LENGTH = 200;
const ALLOWED_CACHE_KEY_PATTERN = /^[a-zA-Z0-9_\-:.]+$/;

async function handleRequest(request) {
  try {
    // Only allow GET and HEAD requests to be cached
    if (request.method !== 'GET' && request.method !== 'HEAD') {
      return fetch(request);
    }

    const url = new URL(request.url);
    
    // Parse and validate query parameters
    const ttlParam = url.searchParams.get('ttl');
    const cacheKeyParam = url.searchParams.get('cache_key');
    
    // Validate and sanitize TTL
    let ttl = DEFAULT_TTL;
    if (ttlParam !== null) {
      const parsedTTL = parseInt(ttlParam, 10);
      if (isNaN(parsedTTL) || parsedTTL < 0) {
        return new Response('Invalid TTL parameter', { status: 400 });
      }
      // Enforce TTL bounds
      ttl = Math.max(MIN_TTL, Math.min(parsedTTL, MAX_TTL));
    }
    
    // Validate and sanitize cache key
    let customCacheKey = null;
    if (cacheKeyParam !== null) {
      // Validate length
      if (cacheKeyParam.length > MAX_CACHE_KEY_LENGTH) {
        return new Response('Cache key too long', { status: 400 });
      }
      
      // Validate format - only allow alphanumeric and safe characters
      if (!ALLOWED_CACHE_KEY_PATTERN.test(cacheKeyParam)) {
        return new Response('Invalid cache key format', { status: 400 });
      }
      
      customCacheKey = cacheKeyParam;
    }
    
    // Remove cache control parameters from URL before forwarding to origin
    url.searchParams.delete('ttl');
    url.searchParams.delete('cache_key');
    
    // Construct cache key
    const cacheKey = customCacheKey 
      ? new Request(`${url.origin}${url.pathname}?cache_key=${customCacheKey}`, {
          method: request.method,
          headers: request.headers
        })
      : new Request(url.toString(), {
          method: request.method,
          headers: request.headers
        });
    
    const cache = caches.default;
    
    // Try to get from cache
    let response = await cache.match(cacheKey);
    
    if (response) {
      // Add header to indicate cache hit
      response = new Response(response.body, response);
      response.headers.set('X-Cache-Status', 'HIT');
      return response;
    }
    
    // Fetch from origin
    const originRequest = new Request(url.toString(), {
      method: request.method,
      headers: request.headers,
      redirect: request.redirect,
      cf: {
        cacheTtl: ttl,
        cacheEverything: true
      }
    });
    
    response = await fetch(originRequest);
    
    // Only cache successful responses
    if (response.ok) {
      // Clone response for caching
      const responseToCache = response.clone();
      
      // Create new response with cache headers
      const headers = new Headers(responseToCache.headers);
      headers.set('Cache-Control', `public, max-age=${ttl}`);
      headers.set('X-Cache-Status', 'MISS');
      
      const cachedResponse = new Response(responseToCache.body, {
        status: responseToCache.status,
        statusText: responseToCache.statusText,
        headers: headers
      });
      
      // Store in cache (non-blocking)
      event.waitUntil(cache.put(cacheKey, cachedResponse.clone()));
      
      return cachedResponse;
    }
    
    // Return non-cacheable response with status header
    response = new Response(response.body, response);
    response.headers.set('X-Cache-Status', 'BYPASS');
    return response;
    
  } catch (error) {
    // Log error without exposing sensitive details
    console.error('Cache worker error:', error.message);
    
    // Return generic error response
    return new Response('Internal Server Error', { 
      status: 500,
      headers: {
        'Content-Type': 'text/plain'
      }
    });
  }
}